original_code:
module TopModule (
    input wire A,
    input wire B,
    input wire S,
    output reg Y
);
    always @(*) begin
        if (S)
            Y = B;
        else
            Y = A;
    end
endmodule

adversarial_code:
module TopModule (
    input wire A,
    input wire B,
    input wire S,
    output wire Y
);
    assign Y = S ? B : A;
endmodule
